export const TextArea = () => {
  const [value, setValue] = useState<string>('');
  const [disabled, setDisabled] = useState<boolean>(false);
  const [error, setError] = useState<boolean>(false);

  return (
    <div>
      <div>
        <span>禁用：</span>
        <Switch checked={disabled} onChange={setDisabled} />
      </div>
      <div>
        <span>错误：</span>
        <Switch checked={error} onChange={setError} />
      </div>
      <Divider text="基础" />
      <Input.TextArea allowClear placeholder="请输入" disabled={disabled} error={error} />
      <Input.TextArea allowClear placeholder="请输入" defaultValue="hello word" disabled={disabled} error={error} />
      <Divider text="展示数量" />
      <Input.TextArea allowClear placeholder="请输入" showCount disabled={disabled} error={error} />
      <Divider text="展示数量 - 设置最大长度" />
      <Input.TextArea
        style={{ width: 300 }}
        allowClear
        placeholder="请输入"
        showCount
        maxLength={100}
        disabled={disabled}
        error={error}
      />
      <Divider text="自适应高度" />
      <Input.TextArea allowClear autoSize placeholder="自适应高度" disabled={disabled} error={error} />
      <Divider text="自适应高度 - 设置最大最小边界（最小5行，最大10行）" />
      <Input.TextArea
        allowClear
        rows={1}
        autoSize={{ minRows: 5, maxRows: 10 }}
        placeholder="自适应高度"
        disabled={disabled}
        error={error}
      />
      <Divider text="受控" />
      <Input.TextArea
        allowClear
        placeholder="请输入"
        value={value}
        onChange={e => setValue(e.target.value)}
        disabled={disabled}
        error={error}
      />
    </div>
  );
};

export const SearchInput = () => {
  const [size, setSize] = useState<DefaultSizeType>('medium');
  const [shape, setShape] = useState<Searchhape>('round');
  const [error, setError] = useState<boolean>(false);

  return (
    <div>
      <div>
        <span>尺寸：</span>
        <Radio.Group defaultValue="medium" onChange={val => setSize(val as DefaultSizeType)}>
          <Radio.Button value="large">大</Radio.Button>
          <Radio.Button value="medium">中</Radio.Button>
          <Radio.Button value="small">小</Radio.Button>
        </Radio.Group>
        <span style={{ marginLeft: 30 }}>形状：</span>
        <Radio.Group defaultValue="round" onChange={val => setShape(val as Searchhape)}>
          <Radio.Button value="round">全圆角</Radio.Button>
          <Radio.Button value="square">矩形</Radio.Button>
        </Radio.Group>
        <span style={{ marginLeft: 30 }}>错误：</span>
        <Switch checked={error} onChange={setError} />
      </div>
      <Divider text="基础" />
      <Input.Search size={size} error={error} shape={shape} allowClear />
      <Divider text="自定义后缀" />
      <Input.Search size={size} error={error} shape={shape} allowClear suffix="(⌘+K)" />
    </div>
  );
};

