export const CounterWithSize = () => (
  <Space size="large" direction="vertical">
    {(['large', 'medium', 'small'] as InputProps['size'][]).map(size => {
      const tagSize: TagProps['size'] = size === 'large' ? 'medium' : 'small';
      return (
        <>
          <h4>Size: {size}</h4>
          <Input showCount={true} maxLength={10} size={size} placeholder="Input password" />
          <Input
            showCount={true}
            maxLength={10}
            counter={str => [...str].length}
            truncateExcessWords
            size={size}
            suffix={<ContactsOutlined />}
            allowClear
            placeholder="Input password"
          />
          <Input
            showCount={true}
            maxLength={10}
            truncateExcessWords
            size={size}
            suffix={
              <Tag size={tagSize} color="neutral-light">
                中文
              </Tag>
            }
            placeholder="Input password"
          />
        </>
      );
    })}
  </Space>
);

export const WithForm = () => {
  const [formValue, setFormValue] = useState<{
    a: string;
    b: string;
    c: string;
    d: string;
  }>({ a: '', b: '', c: '', d: '' });
  return (
    <>
      <p>测试受控值，及中文输入</p>
      <Form initialValues={formValue} onValuesChange={v => setFormValue({ ...formValue, ...v })}>
        <Form.Item name="a" label="最大长度 10">
          <Input maxLength={10} onChange={e => console.log(e.target.value)} />
        </Form.Item>
        <Form.Item name="b" label="Show Counter and truncate">
          <Input
            maxLength={10}
            showCount
            truncateExcessWords
            onCompositionEnd={() => console.log('composition ended')}
            onCompositionStart={() => console.log('composition started')}
            onChange={e => console.log('onChange: ', e.target.value)}
            allowClear
          />
        </Form.Item>
        <Form.Item name="c" label="Show Counter">
          <Input maxLength={10} showCount onChange={e => console.log(e.target.value)} allowClear />
        </Form.Item>
        <Form.Item name="d" label="Show Counter  and truncate">
          <Input.TextArea
            maxLength={10}
            showCount
            truncateExcessWords
            onChange={e => console.log(e.target.value)}
            allowClear
          />
        </Form.Item>
      </Form>
      <p>得到值： {JSON.stringify(formValue)}</p>
    </>
  );
};
